type Winner = 'home' | 'away'

export interface Team {
  name: string
  flag: string
}

export interface MatchSide {
  team: Team | null
  score: number | null
  penalties?: number
}

export interface Match {
  id: string
  date: string
  time?: string
  status: 'finished' | 'upcoming'
  home: MatchSide
  away: MatchSide
  winner?: Winner
}

export interface Round {
  name: string
  matches: Match[]
}

export interface KnockoutControls {
  previous?: () => void
  next?: () => void
  reset?: () => void
}

